typedef struct {
    int (*read)(unsigned char *buf, unsigned int len);
    int (*write)(const unsigned char *buf, unsigned int len);
} comm_port_t;

int protocol_poll(comm_port_t *port) {
    unsigned char frame[64];
    int len = port->read(frame, sizeof(frame));
    if (len <= 0) {
        return 0;
    }

    /* 协议层只处理帧，不关心底层来自 UART、USB CDC 还是 SPI */
    return len;
}

/* bus 层：只负责 I2C 字节传输 */
int i2c_bus_read(unsigned char addr, unsigned char reg, unsigned char *buf, unsigned int len);
int i2c_bus_write(unsigned char addr, unsigned char reg, const unsigned char *buf, unsigned int len);

/* device 层：封装具体芯片寄存器 */
int sensor_read_temperature(int *temperature);

/* app 层：只关心业务阈值和状态 */
void temperature_service_poll(void);

